previewCss:
.darma-loader-uiverse-charging-tower {
  position: relative;
  width: 72px;
  height: 124px;
  border-radius: 8px;
  background-color: #000;
  background-image: radial-gradient(ellipse at center, rgba(0,0,0,1) 0%,rgba(0,0,0,1) 4%,rgba(81,81,81,1) 14%,rgba(44,44,44,1) 26%,rgba(2,2,2,1) 53%,rgba(2,2,2,1) 65%,rgba(2,2,2,0) 66%),
    linear-gradient(#111, #111);
  background-repeat: no-repeat;
  background-size: 9px 9px , 64px 110px;
  background-position: center 2px, 4px 8px;
  animation: darma-loader-uiverse-charging-tower-lightUp 6s linear infinite alternate;
}

.darma-loader-uiverse-charging-tower:before {
content: '';
position: absolute;
left: 50%;
top: 118px;
transform: translateX(-50%);
width: 26px;
height: 44px;
background-image: linear-gradient(#fff, #fff),
linear-gradient(#bbb, #bbb),
linear-gradient(#fff, #fff);
background-repeat: no-repeat;
background-position: center 4px , center top, center 5px;
background-size: 9px 9px , 7px 4px , 2px 100%;
animation: darma-loader-uiverse-charging-tower-plugin 6s linear infinite alternate;
}

.darma-loader-uiverse-charging-tower:after {
content: '';
width: 24px;
height: 48px;
background-image: linear-gradient(#888, #888),
linear-gradient(to right, rgba(255,255,255,0.1) 0%,rgba(255,255,255,0.5) 40%,rgba(255,255,255,0.3) 50%,rgba(255,255,255,0.1) 100%),
linear-gradient(var(--loader-color, #15ff00), var(--loader-color, #15ff00)),
linear-gradient(#888, #888);
background-size: 10px 4px, 24px 42px , 24px 0px , 24px 46px;
background-position: center 0 , center 6px , center bottom , center 4px;
background-repeat: no-repeat;
top: 50%;
left: 50%;
position: absolute;
transform: translate(-50% , -50%);
animation: darma-loader-uiverse-charging-tower-charging 6s linear infinite alternate;
}

@keyframes darma-loader-uiverse-charging-tower-charging {
0% , 25% {
opacity: 0;
background-size: 10px 4px, 24px 42px , 24px 0px , 24px 46px;
}

26% , 75% {
opacity: 1;
background-size: 10px 4px, 24px 42px , 24px 0px , 24px 46px;
}

50% , 100% {
opacity: 1;
background-size: 10px 4px, 24px 42px , 24px 46px , 24px 46px
}
}

@keyframes darma-loader-uiverse-charging-tower-lightUp {
0% , 25% {
background-image: radial-gradient(ellipse at center, rgba(0,0,0,1) 0%,rgba(0,0,0,1) 4%,rgba(81,81,81,1) 14%,rgba(44,44,44,1) 26%,rgba(2,2,2,1) 53%,rgba(2,2,2,1) 65%,rgba(2,2,2,0) 66%),
linear-gradient(#111, #111);
}

26% , 100% {
background-image: radial-gradient(ellipse at center, rgba(0,0,0,1) 0%,rgba(0,0,0,1) 4%,rgba(81,81,81,1) 14%,rgba(44,44,44,1) 26%,rgba(2,2,2,1) 53%,rgba(2,2,2,1) 65%,rgba(2,2,2,0) 66%),
linear-gradient(#DDD, #DDD);
}
}

@keyframes darma-loader-uiverse-charging-tower-plugin {
0% , 25% {
top: 118px;
background-position: center 4px , center top, center 5px;
}

26% , 100% {
background-position: center 0 , center top, center 5px;
top: 110px;
}
}

